/**
 * Device Capability Scoring Engine
 * 
 * Safely analyzes the user's hardware via `navigator.hardwareConcurrency`, `deviceMemory`, 
 * and `performance` timings (handled via `ssrSafe.ts`) to return a tier score.
 * 
 * Tiers:
 * 0: Potato (Disable 3D, Disable Blur, Static Only)
 * 1: Low-End (Low-Res 3D, No Shadows, Demand Frameloop)
 * 2: Mid-Range (Standard 3D, Subtle Shadows)
 * 3: High-End (Full R3F, Dynamic Shadows, Uncapped Frameloop)
 */

import { getSafeNavigator } from '../utils/ssrSafe';

export type DeviceTier = 0 | 1 | 2 | 3;

export function determineDeviceCapability(): DeviceTier {
  const nav = getSafeNavigator();
  if (!nav) return 1; // Default to safe fallback in SSR

  let score = 0;

  // 1. Cores
  const cores = nav.hardwareConcurrency || 4;
  if (cores >= 8) score += 2;
  else if (cores >= 4) score += 1;

  // 2. Memory (Not standard everywhere, but widely available in Chromium)
  const memory = (nav as any).deviceMemory || 4;
  if (memory >= 8) score += 2;
  else if (memory >= 4) score += 1;

  // Final Tier mapping
  if (score >= 4) return 3; // High-End
  if (score >= 2) return 2; // Mid-End
  if (score >= 1) return 1; // Low-End
  return 0; // Potato
}

/**
 * Enterprise Performance Monitor
 * 
 * Captures FCP, LCP, CLS, and Long Tasks (>50ms).
 * Strictly gated by SSR wrappers and Feature Flags.
 */

import { getSafePerformance } from '../utils/ssrSafe';
import { getFeatureFlag } from '../feature-flags/useFeatureFlag';

export function initPerformanceMonitoring() {
  if (!getFeatureFlag('ENABLE_OBSERVABILITY_TELEMETRY')) return;

  const perf = getSafePerformance();
  if (!perf) return;

  try {
    // 1. Core Web Vitals (Using standard PerformanceObserver patterns if available)
    if (typeof PerformanceObserver !== 'undefined') {
      
      // LCP
      new PerformanceObserver((entryList) => {
        const entries = entryList.getEntries();
        const lastEntry = entries[entries.length - 1];
        if (lastEntry.startTime > 2500) {
          console.warn(`[PERF: LCP] Violation: ${lastEntry.startTime.toFixed(2)}ms (Limit: 2500ms)`);
        }
      }).observe({ type: 'largest-contentful-paint', buffered: true });

      // FCP
      new PerformanceObserver((entryList) => {
        const entries = entryList.getEntries();
        if (entries.length > 0) {
          const fcp = entries[0].startTime;
          if (fcp > 1500) {
            console.warn(`[PERF: FCP] Violation: ${fcp.toFixed(2)}ms (Limit: 1500ms)`);
          }
        }
      }).observe({ type: 'paint', buffered: true });

      // CLS
      new PerformanceObserver((entryList) => {
        let clsScore = 0;
        for (const entry of entryList.getEntries()) {
          if (!(entry as any).hadRecentInput) {
            clsScore += (entry as any).value;
          }
        }
        if (clsScore > 0.1) {
          console.warn(`[PERF: CLS] Violation: ${clsScore.toFixed(3)} (Limit: 0.1)`);
        }
      }).observe({ type: 'layout-shift', buffered: true });

      // Long Tasks (> 50ms implies frame drops or main-thread locking)
      new PerformanceObserver((entryList) => {
        for (const entry of entryList.getEntries()) {
          console.warn(`[PERF: LONG TASK] UI Thread blocked for ${entry.duration.toFixed(2)}ms`);
        }
      }).observe({ type: 'longtask', buffered: true });
    }
  } catch {
    // Observers might not be supported in old browsers, silently catch
  }
}

