            disabled={loading}
            className={`w-full mt-6 bg-white text-black py-4 font-semibold uppercase tracking-widest transition-colors duration-300 rounded-sm ${loading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-[var(--color-luxury-gold)] hover:text-white'}`}
          >
            {loading ? 'Submitting...' : 'Submit Application'}
          </button>
        </form>

        <p className="mt-8 text-center text-xs text-white/50 tracking-widest uppercase">
          Already approved? <Link to="/login" className="text-white hover:text-[var(--color-luxury-gold)] transition-colors duration-150">Sign In</Link>
        </p>
      </motion.div>
    </div>
  );
}

/**
 * Application Router
 * 
 * Defines routing architecture, wrapping dynamically imported components
 * in React.Suspense to strictly enforce the chunk limits.
 */
import { createBrowserRouter, RouterProvider } from 'react-router-dom';
import { Suspense, lazy } from 'react';
import { RootLayout } from '../components/layout/RootLayout';

// Tier 3 components must be lazily imported
const Home = lazy(() => import('../pages/Home'));

// Fallback skeleton loader for Suspense bounds
import PageSkeleton from '../components/PageSkeleton';

import Login from '../pages/auth/Login';
import Register from '../pages/auth/Register';

// The explore route is Tier 2 so it can be eagerly imported or lazy loaded, let's eager load here to diversify bundles
import Explore from '../pages/Explore';
import Artists from '../pages/Artists';
import ArtistProfile from '../pages/ArtistProfile';
import Curated from '../pages/Curated';
import Dashboard from '../pages/Dashboard';
import AdminDashboard from '../pages/AdminDashboard';
import Profile from '../pages/Profile';

// Tier 3 Details Page
const ImmersiveDetail = lazy(() => import('../pages/artwork/ImmersiveDetail'));

// Global 404/Error Catch
import ErrorPage from '../pages/ErrorPage';

export const router = createBrowserRouter([
  {
    path: '/',
    element: <RootLayout />,
    errorElement: <ErrorPage />,
    children: [
      {
        index: true,
        element: (
          <Suspense fallback={<PageSkeleton />}>
            <Home />
          </Suspense>
        )
      },
      {
        path: 'login',
        element: <Login />
      },
      {
        path: 'register',
        element: <Register />
      },
      {
